using UnityEngine;

/// <summary>
/// Fragmento Vital — concede <see cref="amount"/> Fragmentos Vitais
/// (<c>PlayerProgress.GiveFragmentosVitais</c>, que converte automaticamente
/// em corações extra ao atingir o limiar configurado) e regista "encontrado"
/// na área (<c>AreaProgress.fragmentsFound</c> / <c>AreaData.totalFragments</c>)
/// uma vez por unidade concedida.
/// </summary>
public class FragmentoVitalPickup : PickupBase
{
    [Header("Fragmento Vital")]
    [Tooltip("Quantidade de Fragmentos Vitais concedidos (normalmente 1).")]
    [Min(1)] public int amount = 1;

    public override PickupType Type => PickupType.FragmentoVital;

    protected override void GrantReward()
    {
        var progress = PlayerProgress.Instance;
        if (progress == null) return;

        progress.GiveFragmentosVitais(amount);

        if (area != null)
            for (int i = 0; i < amount; i++) progress.AddFragmentFound(area);
    }
}
